import java.util.HashMap;
import java.util.Map;

public int countOnceInBoth(String[] words1, String[] words2) {
    Map<String, Integer> counter1 = new HashMap<>();
    Map<String, Integer> counter2 = new HashMap<>();

    for (String word : words1)
        counter1.put(word, counter1.getOrDefault(word, 0) + 1);
    for (String word : words2)
        counter2.put(word, counter2.getOrDefault(word, 0) + 1);

    int count = 0;
    for (Map.Entry<String, Integer> item : counter1.entrySet())
        if (item.getValue() == 1 && counter2.getOrDefault(item.getKey(), 0) == 1)
            count++;

    return count;
}
```

